Nice idea — cute, playful, and very do-able. Below I’m giving you a complete, self-contained React implementation (two files: `App.js` and `App.css`) that matches your spec:

- Login screen with **Enter Password** (password must be **`Payal`** — case-sensitive).
- On correct password: a lock animation opens.
- Then a gift box pops in (clickable).
- First click: lid slides away and a boy peeks.
- Second click: boy comes out fully wearing a **“Vinyas”** t-shirt and holding a heart.
- Third click: a cheerful **Happy New Year 2026** celebration + warm welcome message.

I kept the visuals simple and cute using SVG + CSS animations so it’s lightweight and runs anywhere. You can paste this into a `create-react-app` project (or similar).

---

## Files

### 1) `App.js`
```jsx
import React, { useState, useRef } from "react";
import "./App.css";

export default function App() {
  const [stage, setStage] = useState("login"); // login, unlocking, box, peek, out, celebrate
  const [input, setInput] = useState("");
  const [error, setError] = useState("");
  const boxClickCount = useRef(0);

  // check password:
  function handleSubmit(e) {
    e?.preventDefault();
    setError("");
    if (input === "Payal") {
      setStage("unlocking");
      // after unlocking animation, show box
      setTimeout(() => setStage("box"), 1500);
    } else {
      setError("Incorrect password. Try again.");
    }
  }

  function onBoxClick() {
    // only active when stage === 'box' or later
    if (stage === "box") {
      boxClickCount.current = 1;
      setStage("peek");
    } else if (stage === "peek") {
      boxClickCount.current = 2;
      setStage("out");
    } else if (stage === "out") {
      boxClickCount.current = 3;
      setStage("celebrate");
    }
  }

  return (
    <div className="app">
      <div className="card">
        {stage === "login" && (
          <div className="login">
            <h1 className="headline">Enter Password</h1>
            <form onSubmit={handleSubmit} className="form">
              <input
                aria-label="password"
                autoFocus
                value={input}
                onChange={(e) => setInput(e.target.value)}
                className="pw"
                placeholder="Enter password..."
                type="password"
              />
              <button className="submit">Enter</button>
            </form>
            {error && <div className="error">{error}</div>}

            <div className="hint">Hint: It's her name 😉</div>
          </div>
        )}

        {stage !== "login" && (
          <>
            <div className="scene">
              {/* Lock + unlocking */}
              <div className={`lockwrap ${stage === "unlocking" ? "unlocking" : ""} ${stage !== "unlocking" && stage !== "box" ? "locked-hidden" : ""}`}>
                <svg className="lock" width="110" height="110" viewBox="0 0 100 100">
                  <g transform="translate(50,50)">
                    {/* shackle */}
                    <path className="shackle" d="M-20,-10 A20,20 0 0,1 20,-10" stroke="#5a4b8a" strokeWidth="5" fill="none" strokeLinecap="round"/>
                    {/* body */}
                    <rect x="-26" y="-2" width="52" height="46" rx="6" fill="#6c5ce7" />
                    <circle cx="0" cy="18" r="6" fill="#f6f6ff" />
                  </g>
                </svg>
                <div className="unlock-text">unlocking...</div>
              </div>

              {/* Gift box scene */}
              <div className={`box-area ${stage === "box" ? "box-pop" : ""} ${stage === "peek" ? "box-peek" : ""} ${stage === "out" ? "box-out" : ""} ${stage === "celebrate" ? "box-celebrate" : ""}`}>
                {/* Box (clickable) */}
                <div className="gift" onClick={onBoxClick} role="button" tabIndex={0} aria-pressed="false">
                  {/* lid */}
                  <div className={`lid ${stage === "peek" || stage === "out" || stage === "celebrate" ? "lid-open" : ""}`}></div>
                  {/* box body */}
                  <div className="boxbody">
                    <div className="ribbon"></div>
                  </div>

                  {/* boy peek / out */}
                  <div className={`boy ${stage === "peek" ? "peek" : ""} ${stage === "out" ? "out" : ""}`}>
                    <div className="head">
                      <div className="hair"></div>
                      <div className="eyes">
                        <span className="eye" />
                        <span className="eye" />
                      </div>
                      <div className="smile">☺</div>
                    </div>
                    <div className="torso">
                      <div className="tshirt">Vinyas</div>
                      <div className={`heart ${stage === "out" ? "visible" : ""}`}>❤</div>
                    </div>
                  </div>
                </div>
              </div>

              {/* Celebration */}
              {stage === "celebrate" && (
                <div className="celebrate">
                  <div className="confetti" aria-hidden />
                  <h2>🎉 Happy New Year 2026! 🎉</h2>
                  <p className="welcome">A very warm welcome to you, Payal — wishing you joy, success and lots of smiles.</p>
                </div>
              )}
            </div>
          </>
        )}

        {/* small foot note */}
        <div className="foot">
          {stage === "login" ? (
            <div>Make her enter the password: <strong>Payal</strong></div>
          ) : (
            <div className="tip">{stage === "box" ? "Click the gift!" : stage === "peek" ? "Click again..." : stage === "out" ? "One more time for the surprise!" : ""}</div>
          )}
        </div>
      </div>
    </div>
  );
}
```

