## `App.js`
```jsx
import React, { useState, useRef, useEffect } from "react";
import "./App.css";

/**
 * Interactive surprise:
 * - login (password: "Payal")
 * - unlock animation
 * - gift box clickable with 3-step interaction
 * - SVG boy illustration and animated SVG heart
 * - WebAudio-based sound effects (pop, chime, confetti)
 */

export default function App() {
  const [stage, setStage] = useState("login"); // login, unlocking, box, peek, out, celebrate
  const [input, setInput] = useState("");
  const [error, setError] = useState("");
  const clickCount = useRef(0);
  const audioCtxRef = useRef(null);

  // Initialize Web Audio context lazily on first interaction (to satisfy browser policies)
  function ensureAudio() {
    if (!audioCtxRef.current) {
      const AudioContext = window.AudioContext || window.webkitAudioContext;
      audioCtxRef.current = new AudioContext();
    }
    return audioCtxRef.current;
  }

  // small pop (for lid)
  function playPop() {
    const ctx = ensureAudio();
    if (!ctx) return;
    const o = ctx.createOscillator();
    const g = ctx.createGain();
    o.type = "triangle";
    o.frequency.value = 600;
    g.gain.value = 0.0001;
    o.connect(g);
    g.connect(ctx.destination);

    const now = ctx.currentTime;
    g.gain.setValueAtTime(0.0001, now);
    g.gain.linearRampToValueAtTime(0.12, now + 0.01);
    o.frequency.exponentialRampToValueAtTime(900, now + 0.06);
    g.gain.exponentialRampToValueAtTime(0.0001, now + 0.25);

    o.start(now);
    o.stop(now + 0.28);
  }

  // gentle chime (for unlock)
  function playChime() {
    const ctx = ensureAudio();
    if (!ctx) return;
    const o1 = ctx.createOscillator();
    const o2 = ctx.createOscillator();
    const g = ctx.createGain();

    o1.type = "sine";
    o2.type = "sine";
    o1.frequency.value = 520;
    o2.frequency.value = 680;
    g.gain.value = 0.0001;

    o1.connect(g);
    o2.connect(g);
    g.connect(ctx.destination);

    const now = ctx.currentTime;
    g.gain.linearRampToValueAtTime(0.12, now + 0.02);
    o1.frequency.exponentialRampToValueAtTime(760, now + 0.45);
    o2.frequency.exponentialRampToValueAtTime(980, now + 0.45);
    g.gain.exponentialRampToValueAtTime(0.0001, now + 1.0);

    o1.start(now);
    o2.start(now);
    o1.stop(now + 1.05);
    o2.stop(now + 1.05);
  }

  // confetti / sparkle blast
  function playConfetti() {
    const ctx = ensureAudio();
    if (!ctx) return;
    const now = ctx.currentTime;
    for (let i = 0; i < 6; i++) {
      const o = ctx.createOscillator();
      const g = ctx.createGain();
      o.type = "square";
      o.frequency.value = 300 + Math.random() * 900;
      g.gain.value = 0.0001;
      o.connect(g);
      g.connect(ctx.destination);
      const offset = i * 0.02;
      g.gain.linearRampToValueAtTime(0.09 * Math.random() + 0.05, now + offset + 0.01);
      g.gain.exponentialRampToValueAtTime(0.0001, now + offset + 0.5 + Math.random() * 0.5);
      o.start(now + offset);
      o.stop(now + offset + 0.65 + Math.random() * 0.45);
    }
  }

  // handle password submit
  function handleSubmit(e) {
    e?.preventDefault();
    setError("");
    if (input === "Payal") {
      setStage("unlocking");
      // play chime
      setTimeout(() => {
        playChime();
      }, 50);
      // after unlocking animation, show box
      setTimeout(() => setStage("box"), 1300);
    } else {
      setError("Incorrect password. Try again.");
    }
  }

  function onBoxClick() {
    // ensure audio context is created by user gesture
    ensureAudio();
    if (stage === "box") {
      clickCount.current = 1;
      playPop();
      setStage("peek");
    } else if (stage === "peek") {
      clickCount.current = 2;
      playPop();
      setStage("out");
      // reveal heart shortly after
      setTimeout(() => {
        playConfetti();
      }, 300);
    } else if (stage === "out") {
      clickCount.current = 3;
      playConfetti();
      setStage("celebrate");
    }
  }

  // friendly keyboard: Enter triggers submit in login
  useEffect(() => {
    function onKey(e) {
      if (stage !== "login") return;
      if (e.key === "Enter") {
        handleSubmit(e);
      }
    }
    window.addEventListener("keydown", onKey);
    return () => window.removeEventListener("keydown", onKey);
    // eslint-disable-next-line
  }, [input, stage]);

  return (
    <div className="app">
      <div className="card">
        {stage === "login" && (
          <div className="login">
            <h1 className="headline">Enter Password</h1>
            <form onSubmit={handleSubmit} className="form" onClick={() => ensureAudio()}>
              <input
                aria-label="password"
                autoFocus
                value={input}
                onChange={(e) => setInput(e.target.value)}
                className="pw"
                placeholder="Enter password..."
                type="password"
              />
              <button className="submit" type="submit">Enter</button>
            </form>
            {error && <div className="error">{error}</div>}
            <div className="hint">Hint: It's her name 😉</div>
          </div>
        )}

        {stage !== "login" && (
          <>
            <div className="scene">
              {/* Lock + unlocking */}
              <div className={`lockwrap ${stage === "unlocking" ? "unlocking" : ""} ${stage !== "unlocking" && stage !== "box" ? "locked-hidden" : ""}`}>
                <svg className="lock" width="110" height="110" viewBox="0 0 100 100" aria-hidden>
                  <g transform="translate(50,50)">
                    <path className="shackle" d="M-20,-10 A20,20 0 0,1 20,-10" stroke="#5a4b8a" strokeWidth="5" fill="none" strokeLinecap="round"/>
                    <rect x="-26" y="-2" width="52" height="46" rx="6" fill="#6c5ce7" />
                    <circle cx="0" cy="18" r="6" fill="#f6f6ff" />
                  </g>
                </svg>
                <div className="unlock-text">{stage === "unlocking" ? "unlocking..." : "unlocked"}</div>
              </div>

              {/* Gift box scene */}
              <div className={`box-area ${stage === "box" ? "box-pop" : ""} ${stage === "peek" ? "box-peek" : ""} ${stage === "out" ? "box-out" : ""} ${stage === "celebrate" ? "box-celebrate" : ""}`}>
                <div className="gift" onClick={onBoxClick} role="button" tabIndex={0}>
                  <div className={`lid ${stage === "peek" || stage === "out" || stage === "celebrate" ? "lid-open" : ""}`}></div>
                  <div className="boxbody">
                    <div className="ribbon"></div>
                  </div>

                  {/* boy SVG (peeking/out) */}
                  <div className={`boy ${stage === "peek" ? "peek" : ""} ${stage === "out" ? "out" : ""}`}>
                    <svg className="boy-svg" width="140" height="200" viewBox="0 0 140 200" aria-hidden>
                      {/* head */}
                      <g transform="translate(70,60)">
                        <ellipse cx="0" cy="0" rx="34" ry="36" fill="#ffe7d3" />
                        <path d="M-24,-8 C-18,-18 18,-18 24,-8 L24,-8 C18,-12 -18,-12 -24,-8 Z" fill="#3b2f2f" transform="translate(0,-12)"/>
                        {/* eyes */}
                        <circle cx="-9" cy="4" r="4" fill="#2c2c2c" />
                        <circle cx="9" cy="4" r="4" fill="#2c2c2c" />
                        {/* smile */}
                        <path d="M-8,14 Q0,22 8,14" stroke="#753" strokeWidth="2" fill="none" strokeLinecap="round" />
                      </g>

                      {/* torso & tshirt */}
                      <g transform="translate(70,120)">
                        <rect x="-36" y="0" rx="10" ry="10" width="72" height="62" fill="#7dd3fc"/>
                        <text x="0" y="38" textAnchor="middle" fontSize="12" fontWeight="700" fill="#033" fontFamily="Inter, Arial">VINYAS</text>
                        {/* hands + heart */}
                        <g className={`heart-wrap ${stage === "out" ? "heart-show" : ""}`}>
                          <circle cx="40" cy="36" r="18" fill="none" />
                        </g>
                      </g>
                    </svg>
                    {/* CSS-based heart placed to the side for stronger visual */}
                    <div className={`svg-heart ${stage === "out" ? "heart-animate" : ""}`}>
                      <svg viewBox="0 0 32 32" width="36" height="36" aria-hidden>
                        <path d="M23.6 4.6c-2-2-5.2-2-7.2 0l-.4.4-.4-.4c-2-2-5.2-2-7.2 0-2 2-2 5.2 0 7.2l7.6 7.6 7.6-7.6c2-2 2-5.2 0-7.2z" fill="#ff4d6d"/>
                      </svg>
                    </div>
                  </div>
                </div>
              </div>

              {/* Celebration */}
              {stage === "celebrate" && (
                <div className="celebrate">
                  <div className="confetti" aria-hidden />
                  <h2>🎉 Happy New Year 2026! 🎉</h2>
                  <p className="welcome">A very warm welcome to you, Payal — wishing you joy, success and lots of smiles.</p>
                </div>
              )}
            </div>
          </>
        )}

        {/* footer / tip */}
        <div className="foot">
          {stage === "login" ? (
            <div>Tell her to enter the password: <strong>Payal</strong></div>
          ) : (
            <div className="tip">{stage === "box" ? "Click the gift!" : stage === "peek" ? "Click again..." : stage === "out" ? "One more time for the surprise!" : ""}</div>
          )}
        </div>
      </div>
    </div>
  );
}
