html,body,#root{height:100%}
body{
  margin:0;
  font-family:Inter, system-ui, -apple-system, "Segoe UI", Roboto, "Helvetica Neue", Arial;
  background:linear-gradient(180deg,#eef6ff 0%,var(--bg) 100%);
  display:flex;
  align-items:center;
  justify-content:center;
  padding:32px;
  color:var(--text);
}

.app{width:100%;max-width:880px}
.card{
  background:var(--card);
  border-radius:16px;
  box-shadow:0 12px 40px rgba(15,20,40,0.08);
  padding:20px;
  overflow:hidden;
}

/* LOGIN */
.login{ text-align:center; padding:12px 10px 6px; }
.headline{ font-size:20px; margin:6px 0 12px; color:var(--vio); font-weight:700; }
.form{ display:flex; gap:10px; justify-content:center; align-items:center; }
.pw{
  padding:12px 14px; border-radius:10px; border:1px solid #e6e9ef; width:220px;
  outline:none; font-size:14px; background:#fbfcff;
}
.pw:focus{ box-shadow:0 6px 18px rgba(108,92,231,0.12); border-color:var(--vio); }
.submit{
  background:var(--vio); color:white; border:none; padding:10px 14px; border-radius:10px; font-weight:700; cursor:pointer;
}
.error{ color:#d9534f; margin-top:12px; font-size:13px; }
.hint{ margin-top:10px; color:var(--muted); font-size:13px }

/* Scene area */
.scene{ display:flex; gap:20px; align-items:center; justify-content:center; padding:8px 6px; min-height:380px; position:relative; }

/* Lock */
.lockwrap{ text-align:center; width:160px; transition:all .35s ease; }
.lock{ display:block; margin:10px auto; }
.unlocking .shackle{
  transform-origin:center;
  animation:shackleOpen .9s ease forwards;
}
@keyframes shackleOpen{
  0%{ transform:rotate(0deg); }
  60%{ transform:rotate(-30deg); }
  100%{ transform:rotate(-40deg); opacity:1; }
}
.unlock-text{ font-size:13px; color:var(--muted); margin-top:8px; }

/* Hide lock when moved to box */
.locked-hidden{ opacity:0.0; transform:translateY(-6px); transition:opacity .4s ease; }

/* Box area */
.box-area{ width:460px; height:320px; display:flex; align-items:center; justify-content:center; position:relative; transition:all .4s ease; }
.box-pop{ animation:popIn .38s ease forwards; }
@keyframes popIn{ from{ transform:scale(.6) translateY(20px); opacity:0 } to { transform:none; opacity:1; } }

/* Gift */
.gift{
  width:220px; height:180px; border-radius:12px; position:relative; cursor:pointer; user-select:none;
  display:flex; align-items:flex-start; justify-content:center; transition:transform .22s ease;
}
.gift:active{ transform:translateY(3px); }

.lid{
  position:absolute; top:-28px; width:260px; height:54px; background:linear-gradient(180deg,#ffdca8,#ffb86b);
  border-radius:8px; left:50%; transform:translateX(-50%); transition: transform .7s cubic-bezier(.2,.9,.25,1), opacity .3s;
  box-shadow:0 8px 26px rgba(0,0,0,0.08);
}
.lid::after{
  content:"";
  position:absolute; left:50%; transform:translateX(-50%); top:12px; width:130px; height:7px; background:linear-gradient(90deg,#fff6ea,#fff); border-radius:6px; opacity:.7;
}

/* open */
.lid-open{
  transform:translateX(-50%) translateY(-140px) rotate(-12deg);
  opacity:0.98;
}

/* box body */
.boxbody{
  width:200px; height:140px; background:linear-gradient(180deg,#fff3c6,#ffd86d); border-radius:12px; position:relative; top:20px;
  display:flex; align-items:center; justify-content:center;
  box-shadow:0 12px 30px rgba(0,0,0,0.08);
}
.ribbon{
  position:absolute; width:20px; height:100%; left:50%; transform:translateX(-50%); background:linear-gradient(180deg,var(--ribbon),#ff3b5e);
}
.ribbon::before{
  content:""; position:absolute; top:42%; left:-32px; width:72px; height:30px; background:var(--ribbon); border-radius:8px; transform:rotate(-15deg);
}

/* boy peek */
.boy{
  position:absolute; bottom:36px; display:flex; flex-direction:column; align-items:center; justify-content:flex-start; pointer-events:none;
  transform:translateY(80px); opacity:0; transition:all .55s cubic-bezier(.2,.9,0.3,1);
  width:180px;
}
.boy.peek{ transform:translateY(18px); opacity:1; }
.boy.out{ transform:translateY(-4px) scale(1.02); opacity:1; }

/* heart (CSS) */
.svg-heart{
  position:absolute; right:12px; bottom:40px; pointer-events:none; opacity:0; transform:translateY(8px) scale(.8);
  transition:all .45s cubic-bezier(.2,.9,0.3,1);
}
.heart-animate{ opacity:1; transform:translateY(0) scale(1.06); animation:heartBeat 1s ease infinite 0.8s; }
@keyframes heartBeat{
  0%{ transform:scale(1) }
  30%{ transform:scale(1.2) }
  60%{ transform:scale(0.95) }
  100%{ transform:scale(1) }
}

/* celebration */
.celebrate{ text-align:center; padding:18px; animation:celebrateIn .6s ease forwards; }
@keyframes celebrateIn{ from{ transform:translateY(20px); opacity:0 } to { transform:none; opacity:1 } }

.confetti{
  position:absolute; left:4%; top:6%; width:92%; height:60%; pointer-events:none;
  background-image: radial-gradient(#ffd6e0 2px, transparent 3px), radial-gradient(#ffd6e0 2px, transparent 3px);
  background-size: 18px 18px, 26px 26px;
  opacity:0.9;
}

/* small foot */
.foot{ margin-top:14px; text-align:center; color:var(--muted); font-size:13px; }

/* responsive */
@media (max-width:720px){
  .scene{ flex-direction:column; min-height:420px; }
  .lockwrap{ order:2; margin-top:20px; }
  .box-area{ order:1; margin-bottom:8px; }
}
```

