    playPop();
    tip.textContent = 'Click again...';
    stage = 'peek';
  }

  function revealOut(){
    clicks = 2;
    lid.classList.add('open');
    boy.classList.remove('peek'); boy.classList.add('out');
    // reveal svg heart
    setTimeout(()=> {
      svgHeart.style.opacity = '1';
      svgHeart.style.transform = 'translateY(0)';
      playPop();
    }, 240);
    tip.textContent = 'One more time for the surprise!';
    stage = 'out';
  }

  function revealCelebrate(){
    clicks = 3;
    stage = 'celebrate';
    // play confetti sound then show typed message then confetti visuals
    playConfetti();
    // start typed message, then show confetti DOM
    startTyping("Hey Payal — welcome to 2026! 🎊");
  }

  // typing effect
  function startTyping(text){
    typedMsg.textContent = '';
    let i = 0;
    const speed = 45; // ms per char
    celebrate.classList.add('show');
    celebrate.setAttribute('aria-hidden','false');
    function step(){
      if(i < text.length){
        typedMsg.textContent += text[i++];
        setTimeout(step, speed);
      } else {
        // after typing finished, show confetti DOM pieces
        runConfetti();
      }
    }
    step();
  }

  function runConfetti(){
    const colors = ['#ff6b81','#ffd86d','#7dd3fc','#b39cff','#ff9aa2'];
    for(let i=0;i<28;i++){
      const el = document.createElement('i');
      el.style.left = (Math.random()*100) + '%';
      el.style.background = colors[Math.floor(Math.random()*colors.length)];
      el.style.top = (Math.random()*10 - 5) + '%';
      el.style.transform = 'rotate('+ (Math.random()*360) +'deg)';
      el.style.animationDelay = (Math.random()*400) + 'ms';
      confetti.appendChild(el);
      setTimeout(()=> el.remove(), 2600);
    }
    // reveal svg heart element (bigger) smoothly
    if(svgHeart) {
      svgHeart.style.transition = 'opacity .4s ease, transform .45s ease';
      svgHeart.style.opacity = '1';
      svgHeart.style.transform = 'translateY(0)';
    }
  }

  // clicking the gift box
  function onGiftClick(e){
    e && e.preventDefault();
    ensureAudio();
    if(stage === 'box' && clicks === 0){
      revealPeek();
    } else if((stage === 'peek' && clicks === 1) || (clicks === 1 && stage === 'box')){
      revealOut();
    } else if((stage === 'out' && clicks === 2) || (clicks === 2 && stage !== 'locked')){
      revealCelebrate();
    }
  }

  gift.addEventListener('click', function(e){
    if(stage === 'box' || stage === 'peek' || stage === 'out') {
      onGiftClick(e);
    }
  });
  gift.addEventListener('keydown', function(e){
    if(e.key === 'Enter' || e.key === ' ') onGiftClick(e);
  });

  // init
  (function init(){
    stage = 'locked';
    tip.textContent = 'Tip: Ask her to enter the password Payal';
    // hide svgHeart initial
    if(svgHeart){ svgHeart.style.opacity = 0; svgHeart.style.transform = 'translateY(8px)'; }
  })();

  // prevent selection drag on gift for UX
  gift.addEventListener('mousedown', e => e.preventDefault());

  // ensure first gesture creates audio ctx in mobile: also call ensureAudio on first touch
  window.addEventListener('touchstart', function once(){ ensureAudio(); window.removeEventListener('touchstart', once); }, {passive:true});

})();
</script>
</body>
</html>
