/* Single-file timeline-coded interactive surprise.
   Flow:
   - login visible only
   - correct password -> show lock -> unlock anim -> hide lock
   - then gift slides in -> first click: lid opens -> chibi peeks (long rise)
   - second click: chibi fully out, big heart appears (heart beat anim)
   - third click: celebration overlay with typed message + confetti
   Audio: small synths via WebAudio; audio ctx created on first gesture.
*/

(function(){
  // DOM
  const loginScreen = document.getElementById('loginScreen');
  const pw = document.getElementById('pw');
  const enterBtn = document.getElementById('enterBtn');
  const lockStage = document.getElementById('lockStage');
  const lockStatus = document.getElementById('lockStatus');
  const shackle = document.getElementById('shackle');
  const giftStage = document.getElementById('giftStage');
  const giftBox = document.getElementById('giftBox');
  const lid = document.getElementById('lid');
  const chibi = document.getElementById('chibi');
  const bigHeart = document.getElementById('bigHeart');
  const celebrate = document.getElementById('celebrate');
  const typedText = document.getElementById('typedText');
  const confettiLayer = document.getElementById('confettiLayer');
  const tip = document.getElementById('tip');

  let audioCtx = null;
  function ensureAudio() {
    if (!audioCtx) {
      try {
        const AudioContext = window.AudioContext || window.webkitAudioContext;
        audioCtx = new AudioContext();
      } catch(e) {
        audioCtx = null;
      }
    }
    return audioCtx;
  }

  // small chime for unlock
  function playChime(){
    const ctx = ensureAudio(); if(!ctx) return;
    const o1 = ctx.createOscillator(); const o2 = ctx.createOscillator(); const g = ctx.createGain();
    o1.type='sine'; o2.type='sine'; o1.frequency.value=520; o2.frequency.value=680; g.gain.value=0.0001;
    o1.connect(g); o2.connect(g); g.connect(ctx.destination);
    const now = ctx.currentTime;
    g.gain.linearRampToValueAtTime(0.12, now+0.02);
    o1.frequency.exponentialRampToValueAtTime(760, now+0.7);
    o2.frequency.exponentialRampToValueAtTime(980, now+0.7);
    g.gain.exponentialRampToValueAtTime(0.0001, now+1.2);
    o1.start(now); o2.start(now); o1.stop(now+1.25); o2.stop(now+1.25);
  }
  // pop for lid
  function playPop(){
    const ctx = ensureAudio(); if(!ctx) return;
    const o = ctx.createOscillator(); const g = ctx.createGain();
    o.type='triangle'; o.frequency.value=700; g.gain.value=0.0001; o.connect(g); g.connect(ctx.destination);
    const now = ctx.currentTime;
    g.gain.linearRampToValueAtTime(0.14, now+0.01);
    o.frequency.exponentialRampToValueAtTime(1100, now+0.08);
    g.gain.exponentialRampToValueAtTime(0.0001, now+0.24);
    o.start(now); o.stop(now+0.28);
  }
  // confetti burst
  function playConfettiSound(){
    const ctx = ensureAudio(); if(!ctx) return;
    const now = ctx.currentTime;
    for(let i=0;i<6;i++){
      const o = ctx.createOscillator(); const g = ctx.createGain();
      o.type='square'; o.frequency.value = 200 + Math.random()*900; g.gain.value=0.0001;
      o.connect(g); g.connect(ctx.destination);
      const off = i*0.02;
      g.gain.linearRampToValueAtTime(0.06 + Math.random()*0.06, now+off+0.01);
      g.gain.exponentialRampToValueAtTime(0.0001, now+off+0.6 + Math.random()*0.5);
      o.start(now+off); o.stop(now+off+0.8 + Math.random()*0.5);
    }
  }

  // state
  let stage = 'login'; // login -> lock -> gift -> peek -> out -> celebrate
  let clicks = 0;

  // utilities
  function sleep(ms){ return new Promise(res=>setTimeout(res, ms)); }

  // password submit
  async function onEnter(e){
    e && e.preventDefault();
    ensureAudio();
    if (pw.value === 'Payal'){
      // hide login, show lock
      loginScreen.classList.add('login-hidden');
      await sleep(380);
      showLockSequence();
    } else {
      // shake input
      pw.animate([{transform:'translateX(0)'},{transform:'translateX(-8px)'},{transform:'translateX(8px)'},{transform:'translateX(0)'}],{duration:350});
      // small hint
      tip.textContent = 'Incorrect — try again';
      setTimeout(()=> tip.textContent = 'Tip: password is Payal', 1600);
    }
  }

  enterBtn.addEventListener('click', onEnter);
  pw.addEventListener('keydown', function(e){ if(e.key === 'Enter') onEnter(); });

  // LOCK sequence
  async function showLockSequence(){
    stage = 'lock';
    lockStage.classList.add('lock-show');
    lockStage.setAttribute('aria-hidden','false');
    lockStatus.textContent = 'Locked';
    await sleep(400);
    // animate shackle open with CSS by toggling class on parent
    lockStage.classList.add('opening');
    // play chime + small mechanical movements
    playChime();
    // show unlocking text
    lockStatus.textContent = 'Unlocking...';
    // wait for effect (longer to build drama) -> 1800ms
    await sleep(1800);
    // fully unlocked & fade out
    lockStatus.textContent = 'Unlocked';
    // small pause to savor
    await sleep(800);
    // fade lock away
    lockStage.classList.remove('lock-show');
    lockStage.setAttribute('aria-hidden','true');
    // now show gift
    await sleep(240);
    await showGift();
  }

  // gift appears
  async function showGift(){
    stage = 'gift';
    giftStage.classList.add('gift-visible');
    giftStage.setAttribute('aria-hidden','false');
    tip.textContent = 'Click the gift to open';
    // subtle entrance audio? small pop
    playPop();
    // keep gift interactive
  }

  // gift click handler (3 clicks progress)
  async function onGiftClick(e){
    if (stage === 'gift' && clicks === 0){
      // first click -> lid opens + chibi peek
      clicks = 1;
      lid.classList.add('open');
      playPop();
      // show chibi peek slowly (long reveal so overall duration increases)
      chibi.classList.add('peek');
      // long "rise" for chibi: animate transform over 12s via CSS transitions already set; we fudge by waiting
      tip.textContent = 'She peeks...';
      // Wait longer so audience can watch: let's wait 14 seconds (long reveal)
      await sleep(14000);
      tip.textContent = 'Click again to bring him out';
      stage = 'peek';
    } else if ((stage === 'peek' && clicks === 1) || (stage === 'gift' && clicks === 1)){
      // second click -> chibi fully out, big heart appears, heart beat begins
      clicks = 2;
      // transition chibi to out state
      chibi.classList.remove('peek'); chibi.classList.add('out');
      // reveal big heart after small delay
      await sleep(600);
      bigHeart.style.opacity = '1';
      bigHeart.style.transform = 'translateY(0)';
      // find heart path and add beat class using a small SVG insertion
      const heartPath = document.getElementById('heartPath') || null;
      // animate scaling via CSS class on parent g element by toggling a class on heartPath or bigHeart
      // we'll create a simple heartbeat loop using CSS class adding
      const heartEl = document.getElementById('bigHeart');
      if (heartEl) {
        heartEl.style.transition = 'opacity .4s ease, transform .4s ease';
        heartEl.style.opacity = 1;
        // start beat via transform scale periodically
        heartEl.classList.add('heart-beat');
      }
      playPop();
      tip.textContent = 'He holds the heart — click once more for New Year!';
      // keep this stage visible for ~14 seconds to reach your ~1 minute total when combined
      await sleep(14000);
      stage = 'out';
    } else if ((stage === 'out' && clicks === 2) || clicks === 2){
      // third click -> celebration
      clicks = 3;
      await showCelebration();
    }
  }

  giftBox.addEventListener('click', function(e){
    if (stage === 'gift' || stage === 'peek' || stage === 'out') onGiftClick(e);
  });

  giftBox.addEventListener('keydown', function(e){
    if (e.key === 'Enter' || e.key === ' ') {
      if (stage === 'gift' || stage === 'peek' || stage === 'out') onGiftClick(e);
    }
  });

  // Celebration sequence: show typed text + confetti + sound
  async function showCelebration(){
    stage = 'celebrate';
    // show overlay
    celebrate.classList.add('show');
    celebrate.setAttribute('aria-hidden','false');
    tip.textContent = 'Happy New Year!';
    // confetti visuals
    makeConfetti();
    // confetti sound
    playConfettiSound();
    // typing message slowly (~18s) to extend total run time
    const message = "A beautiful new year begins… thank you for being part of it.";
    await typeTextSlowly(message, 18 * 1000); // 18 seconds type
    // leave confetti for a few seconds
    await sleep(3500);
    tip.textContent = 'Enjoy the moment ✨';
  }

  // typing helper that types the given text over totalMs duration
  async function typeTextSlowly(text, totalMs){
    typedText.textContent = '';
    const chars = text.length;
    if(chars === 0) return;
    const per = Math.max(20, Math.floor(totalMs / chars));
    for(let i=0;i<chars;i++){
      typedText.textContent += text[i];
      await sleep(per);
    }
  }

  // confetti DOM creation
  function makeConfetti(){
    const colors = ['#ff6b81','#ffd86d','#7dd3fc','#b39cff','#ff9aa2','#9be7a0'];
    // create ~40 pieces
    for(let i=0;i<40;i++){
      const el = document.createElement('div');
      el.className = 'confetti-piece';
      el.style.left = (Math.random()*100) + '%';
      el.style.background = colors[Math.floor(Math.random()*colors.length)];
      el.style.top = (Math.random()*6 - 6) + '%';
      el.style.transform = 'rotate(' + (Math.random()*360) + 'deg)';
      el.style.animationDelay = (Math.random()*600) + 'ms';
      confettiLayer.appendChild(el);
      setTimeout(()=> el.remove(), 3200);
    }
  }

  // initialize - hide lock and gift until ready
  (function init(){
    // hide lock, gift, chibi, celebrate
    lockStage.classList.remove('lock-show');
    giftStage.classList.remove('gift-visible');
    chibi.classList.remove('peek'); chibi.classList.remove('out');
    bigHeart.style.opacity = 0;
    bigHeart.style.transform = 'translateY(8px)';
    celebrate.classList.remove('show');
    tip.textContent = 'Tip: Enter password to begin';
    // make lid closed initially
    lid.classList.remove('open');
  })();

  // Accessibility: create audio ctx on first interaction for mobile
  window.addEventListener('touchstart', function once(){ ensureAudio(); window.removeEventListener('touchstart', once); }, {passive:true});

  // small safety: prevent text selection on gift
  giftBox.addEventListener('mousedown', e => e.preventDefault());

})();
</script>
</body>
